    76→namespace App\Models;
    77→
    78→use Illuminate\Database\Eloquent\Model;
    79→use Illuminate\Database\Eloquent\Relations\BelongsTo;
    80→use Illuminate\Database\Eloquent\Relations\MorphTo;
    81→
    82→class ActivityLog extends Model
    83→{
    84→    public $timestamps = false;
    85→
    86→    protected $fillable = [
    87→        'loggable_type',
    88→        'loggable_id',
    89→        'user_id',
    90→        'event',
    91→        'old_values',
    92→        'new_values',
    93→        'created_at',
