    95→
    96→    protected $casts = [
    97→        'old_values'  => 'array',
    98→        'new_values'  => 'array',
    99→        'created_at'  => 'datetime',
   100→    ];
   101→
   102→    public function loggable(): MorphTo
   103→    {
   104→        return $this->morphTo();
   105→    }
   106→
   107→    public function user(): BelongsTo
   108→    {
   109→        return $this->belongsTo(User::class);
   110→    }
   111→
   112→    public function scopeForLoggable($query, string $type, int $id)
   113→    {
   114→        return $query->where('loggable_type', $type)->where('loggable_id', $id);
   115→    }
   116→}
