   163→        $project = Project::factory()->create(['user_id' => $this->user->id]);
   164→
   165→        expect(ActivityLog::count())->toBe(1);
   166→        $log = ActivityLog::first();
   167→        expect($log->event)->toBe('created');
   168→        expect($log->loggable_type)->toBe(Project::class);
   169→        expect($log->loggable_id)->toBe($project->id);
   170→        expect($log->user_id)->toBe($this->user->id);
   171→        expect($log->old_values)->toBeNull();
   172→        expect($log->new_values)->toHaveKey('name');
   173→    });
   174→
   175→    it('logs an updated event when a watched attribute changes on a project', function () {
   176→        $project = Project::factory()->create(['user_id' => $this->user->id, 'name' => 'Old Name']);
   177→        ActivityLog::truncate();
   178→
   179→        $project->update(['name' => 'New Name']);
   180→
   181→        expect(ActivityLog::count())->toBe(1);
   182→        $log = ActivityLog::first();
   183→        expect($log->event)->toBe('updated');
   184→        expect($log->old_values)->toBe(['name' => 'Old Name']);
   185→        expect($log->new_values)->toBe(['name' => 'New Name']);
   186→    });
   187→
   188→    it('does not log when only unwatched attributes change on a task', function () {
   189→        $project = Project::factory()->create(['user_id' => $this->user->id]);
   190→        $task = Task::factory()->create(['project_id' => $project->id]);
   191→        ActivityLog::truncate();
   192→
   193→        $task->update(['position' => 99]);
   194→
   195→        expect(ActivityLog::count())->toBe(0);
   196→    });
   197→
   198→    it('logs a deleted event when a project is deleted', function () {
   199→        $project = Project::factory()->create(['user_id' => $this->user->id]);
   200→        $projectId = $project->id;
   201→        ActivityLog::truncate();
   202→
   203→        $project->delete();
   204→
   205→        expect(ActivityLog::count())->toBe(1);
   206→        $log = ActivityLog::first();
   207→        expect($log->event)->toBe('deleted');
   208→        expect($log->loggable_id)->toBe($projectId);
   209→        expect($log->old_values)->toHaveKey('name');
   210→        expect($log->new_values)->toBeNull();
   211→    });
   212→
   213→    it('does not log when no watched attribute changes', function () {
   214→        $project = Project::factory()->create(['user_id' => $this->user->id]);
   215→        ActivityLog::truncate();
   216→
   217→        // Saving with the same values — getDirty() will be empty
   218→        $project->update(['name' => $project->name]);
   219→
   220→        expect(ActivityLog::count())->toBe(0);
   221→    });
   222→
   223→    it('does not crash when there is no authenticated user (seeder context)', function () {
   224→        auth()->logout();
   225→
   226→        $project = Project::factory()->create(['user_id' => $this->user->id]);
   227→
   228→        // Should log nothing when not authenticated (guard prevents it)
   229→        expect(ActivityLog::count())->toBe(0);
   230→    });
   231→
   232→    it('logs status change when a task status is updated', function () {
   233→        $project = Project::factory()->create(['user_id' => $this->user->id]);
   234→        $task = Task::factory()->create(['project_id' => $project->id, 'status' => 'backlog']);
   235→        ActivityLog::truncate();
   236→
   237→        $task->update(['status' => 'in_progress', 'position' => 0]);
   238→
   239→        expect(ActivityLog::count())->toBe(1);
   240→        $log = ActivityLog::first();
   241→        expect($log->event)->toBe('updated');
   242→        expect($log->new_values)->toBe(['status' => 'in_progress']);
   243→        expect($log->old_values)->toBe(['status' => 'backlog']);
   244→    });
   245→
   246→});
